import './App.css';
import credenciales_Usuario from './componentes/credenciales'

function App() {
  const [data, setData] = useState([])
  useEffect(()=>{
    fetch('http://localhost:8081/usuarios')
    .then(res => res.json())
    .then(data => setData(data))
    .catch(err => console.log(err));
  },[])
  console.log(credenciales_Usuario)
  return (
    
    <div className="App">
      <credenciales_Usuario />
      <h1>Prueba</h1>
      
    </div>
  
  );
}

export default App;
